    pub fn new(rb: R) -> Self {
        Self { frozen: Frozen::new(rb) }
    }

    /// Get ring buffer observer.
    pub fn observe(&self) -> Obs<R> {
        self.frozen.observe()
    }

    /// Freeze current state.
    pub fn freeze(self) -> Frozen<R, P, C> {
        self.frozen
    }
